@using sv_e084aeefa30a434eb3ad6e8eac993555.Models

<nav class="settings-sidebar">
    <h5 class="px-3 py-2 text-muted mb-1">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link w-100 text-start @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section)">
                    <span class="me-2">@GetIcon(section)</span>@section
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

.settings-sidebar {
    min-width: 200px;
    border-right: 1px solid #dee2e6;
    padding: 1rem 0;
    background: #f8f9fa;
    min-height: 100%;
}

.settings-sidebar .nav-link {
    color: #495057;
    border-radius: 0;
    padding: 0.6rem 1rem;
    border-left: 3px solid transparent;
    transition: all 0.15s ease;
}

.settings-sidebar .nav-link:hover {
    background: #e9ecef;
    color: #212529;
}

.settings-sidebar .nav-link.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

@using sv_e084aeefa30a434eb3ad6e8eac993555.Models

<div class="profile-section">
    <h4 class="mb-4">Profile Settings</h4>

    <div class="d-flex align-items-center mb-4">
        <div class="avatar-preview me-3">
            <img src="@AvatarUrl" alt="Avatar" class="rounded-circle" width="80" height="80" />
        </div>
        <div class="flex-grow-1">
            <label class="form-label text-muted small mb-1">Avatar URL</label>
            <input type="text" class="form-control form-control-sm" value="@AvatarUrl"
                   @oninput="e => AvatarUrl = e.Value?.ToString() ?? string.Empty" />
        </div>
    </div>

    <div class="mb-3">
        <label class="form-label">Display Name</label>
        <input type="text" class="form-control" value="@DisplayName"
               @oninput="e => DisplayName = e.Value?.ToString() ?? string.Empty" />
    </div>

    <div class="mb-3">
        <label class="form-label">Email</label>
        <input type="email" class="form-control" value="@Email"
               @oninput="e => Email = e.Value?.ToString() ?? string.Empty" />
    </div>

    <div class="mb-3">
        <label class="form-label">Bio</label>
        <textarea class="form-control" rows="4" @oninput="e => Bio = e.Value?.ToString() ?? string.Empty">@Bio</textarea>
    </div>

    <div class="d-flex gap-2">
        <button class="btn btn-primary" @onclick="Save" disabled="@IsSaving">
            @if (IsSaving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Changes
        </button>
        <button class="btn btn-outline-secondary" @onclick="Discard">Discard Changes</button>
    </div>

    @if (ShowSuccess)
    {
        <div class="alert alert-success mt-3 d-flex align-items-center" role="alert">
            <span class="me-2">✅</span> Profile saved successfully!
        </div>
    }
</div>

@code {
    [Parameter] public UserProfile? Profile { get; set; }
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string DisplayName = "";
    private string Email = "";
    private string AvatarUrl = "";
    private string Bio = "";
    private bool IsSaving;
    private bool ShowSuccess;

    protected override void OnParametersSet()
    {
        if (Profile is not null && !_initialized)
        {
            ResetFields();
            _initialized = true;
        }
    }

    private bool _initialized;

    private void ResetFields()
    {
        if (Profile is null) return;
        DisplayName = Profile.DisplayName;
        Email = Profile.Email;
        AvatarUrl = Profile.AvatarUrl;
        Bio = Profile.Bio;
    }

    private async Task Save()
    {
        IsSaving = true;
        ShowSuccess = false;
        var updated = new UserProfile(DisplayName, Email, AvatarUrl, Bio);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        ShowSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private void Discard()
    {
        ResetFields();
        ShowSuccess = false;
    }
}

.avatar-preview img {
    object-fit: cover;
    border: 3px solid #dee2e6;
}

@using sv_e084aeefa30a434eb3ad6e8eac993555.Models

<div class="notifications-section">
    <h4 class="mb-4">Notification Preferences</h4>

    <div class="card mb-4">
        <div class="card-body">
            <h6 class="card-title mb-3">General</h6>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="emailNotif"
                       checked="@EmailNotifications"
                       @onchange="e => EmailNotifications = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="emailNotif">
                    Email Notifications
                    <small class="d-block text-muted">Receive notifications via email</small>
                </label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="pushNotif"
                       checked="@PushNotifications"
                       @onchange="e => PushNotifications = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="pushNotif">
                    Push Notifications
                    <small class="d-block text-muted">Receive push notifications in your browser</small>
                </label>
            </div>

            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="weeklyDigest"
                       checked="@WeeklyDigest"
                       @onchange="e => WeeklyDigest = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="weeklyDigest">
                    Weekly Digest
                    <small class="d-block text-muted">Get a weekly summary of activity</small>
                </label>
            </div>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h6 class="card-title mb-3">Muted Channels</h6>
            <p class="text-muted small">Muted channels won't send you any notifications.</p>

            @if (AllChannels.Count > 0)
            {
                @foreach (var channel in AllChannels)
                {
                    <div class="form-check mb-2">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                               checked="@MutedChannels.Contains(channel)"
                               @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="@($"ch-{channel}")">#@channel</label>
                    </div>
                }
            }
        </div>
    </div>

    <button class="btn btn-primary" @onclick="Save" disabled="@IsSaving">
        @if (IsSaving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save Preferences
    </button>

    @if (ShowSuccess)
    {
        <div class="alert alert-success mt-3">✅ Notification preferences saved!</div>
    }
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool EmailNotifications;
    private bool PushNotifications;
    private bool WeeklyDigest;
    private List<string> MutedChannels = [];
    private List<string> AllChannels = [];
    private bool IsSaving;
    private bool ShowSuccess;
    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !_initialized)
        {
            EmailNotifications = Prefs.EmailNotifications;
            PushNotifications = Prefs.PushNotifications;
            WeeklyDigest = Prefs.WeeklyDigest;
            AllChannels = new List<string>(Prefs.MutedChannels);
            MutedChannels = new List<string>(Prefs.MutedChannels);
            _initialized = true;
        }
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted && !MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
        else if (!muted)
            MutedChannels.Remove(channel);
    }

    private async Task Save()
    {
        IsSaving = true;
        ShowSuccess = false;
        var updated = new NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, new List<string>(MutedChannels));
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        ShowSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

