<div class="active-sessions">
    <h6 class="mb-3">Active Sessions</h6>

    @if (Sessions.Count == 0)
    {
        <p class="text-muted">No active sessions found.</p>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-hover align-middle">
                <thead class="table-light">
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>
                                <span class="text-muted small">@FormatLastActive(session.LastActive)</span>
                            </td>
                            <td class="text-end">
                                @if (session.Id != CurrentSessionId)
                                {
                                    <button class="btn btn-outline-danger btn-sm"
                                            @onclick="() => RequestRevoke(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="badge bg-success">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }

    <RevokeSessionDialog Visible="@_showConfirmDialog"
                         Device="@_revokeTarget?.Device"
                         Location="@_revokeTarget?.Location"
                         OnConfirm="ConfirmRevoke"
                         OnCancel="CancelRevoke" />
</div>

@code {
    [Parameter] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private bool _showConfirmDialog;
    private ActiveSession? _revokeTarget;

    private void RequestRevoke(ActiveSession session)
    {
        _revokeTarget = session;
        _showConfirmDialog = true;
    }

    private async Task ConfirmRevoke()
    {
        if (_revokeTarget is not null)
        {
            await OnRevoke.InvokeAsync(_revokeTarget.Id);
        }
        _showConfirmDialog = false;
        _revokeTarget = null;
    }

    private void CancelRevoke()
    {
        _showConfirmDialog = false;
        _revokeTarget = null;
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

