    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string Theme = "Light";
    private string FontSize = "Medium";
    private string Language = "English";
    private bool CompactMode;
    private bool IsSaving;
    private bool ShowSuccess;
    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_initialized)
        {
            Theme = Settings.Theme;
            FontSize = Settings.FontSize;
            Language = Settings.Language;
            CompactMode = Settings.CompactMode;
            _initialized = true;
        }
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(Theme switch
        {
            "Dark" => "preview-dark",
            "System" => "preview-system",
            _ => "preview-light"
        });
        classes.Add(FontSize switch
        {
            "Small" => "preview-font-sm",
            "Large" => "preview-font-lg",
            _ => "preview-font-md"
        });
        if (CompactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private async Task Save()
    {
        IsSaving = true;
        ShowSuccess = false;
        var updated = new AppearanceSettings(Theme, FontSize, Language, CompactMode);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        ShowSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}
