@using sv_e084aeefa30a434eb3ad6e8eac993555.Models

<div class="notifications-section">
    <h4 class="mb-4">Notification Preferences</h4>

    <div class="card mb-4">
        <div class="card-body">
            <h6 class="card-title mb-3">General</h6>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="emailNotif"
                       checked="@EmailNotifications"
                       @onchange="e => EmailNotifications = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="emailNotif">
                    Email Notifications
                    <small class="d-block text-muted">Receive notifications via email</small>
                </label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="pushNotif"
                       checked="@PushNotifications"
                       @onchange="e => PushNotifications = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="pushNotif">
                    Push Notifications
                    <small class="d-block text-muted">Receive push notifications in your browser</small>
                </label>
            </div>

            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" id="weeklyDigest"
                       checked="@WeeklyDigest"
                       @onchange="e => WeeklyDigest = (bool)(e.Value ?? false)" />
                <label class="form-check-label" for="weeklyDigest">
                    Weekly Digest
                    <small class="d-block text-muted">Get a weekly summary of activity</small>
                </label>
            </div>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h6 class="card-title mb-3">Muted Channels</h6>
            <p class="text-muted small">Muted channels won't send you any notifications.</p>

            @if (AllChannels.Count > 0)
            {
                @foreach (var channel in AllChannels)
                {
                    <div class="form-check mb-2">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                               checked="@MutedChannels.Contains(channel)"
                               @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="@($"ch-{channel}")">#@channel</label>
                    </div>
                }
            }
        </div>
    </div>

    <button class="btn btn-primary" @onclick="Save" disabled="@IsSaving">
        @if (IsSaving)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Save Preferences
    </button>

    @if (ShowSuccess)
    {
        <div class="alert alert-success mt-3">✅ Notification preferences saved!</div>
    }
</div>

@code {
    [Parameter] public NotificationPrefs? Prefs { get; set; }
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool EmailNotifications;
    private bool PushNotifications;
    private bool WeeklyDigest;
    private List<string> MutedChannels = [];
    private List<string> AllChannels = [];
    private bool IsSaving;
    private bool ShowSuccess;
    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Prefs is not null && !_initialized)
        {
            EmailNotifications = Prefs.EmailNotifications;
            PushNotifications = Prefs.PushNotifications;
            WeeklyDigest = Prefs.WeeklyDigest;
            AllChannels = new List<string>(Prefs.MutedChannels);
            MutedChannels = new List<string>(Prefs.MutedChannels);
            _initialized = true;
        }
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted && !MutedChannels.Contains(channel))
            MutedChannels.Add(channel);
        else if (!muted)
            MutedChannels.Remove(channel);
    }

    private async Task Save()
    {
        IsSaving = true;
        ShowSuccess = false;
        var updated = new NotificationPrefs(EmailNotifications, PushNotifications, WeeklyDigest, new List<string>(MutedChannels));
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        ShowSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

