@using sv_e084aeefa30a434eb3ad6e8eac993555.Models

<div class="security-section">
    <h4 class="mb-4">Security Settings</h4>

    <div class="card mb-4">
        <div class="card-body">
            <ChangePasswordPanel OnChangePassword="OnChangePassword" />
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center">
                <div>
                    <h6 class="mb-1">Two-Factor Authentication</h6>
                    <p class="text-muted small mb-0">
                        Add an extra layer of security to your account.
                    </p>
                </div>
                <div class="d-flex align-items-center gap-2">
                    <span class="badge @(TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(TwoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                    <div class="form-check form-switch mb-0">
                        <input class="form-check-input" type="checkbox"
                               checked="@TwoFactorEnabled"
                               @onchange="e => ToggleTwoFactor((bool)(e.Value ?? false))" />
                    </div>
                </div>
            </div>
            @if (LastPasswordChange.HasValue)
            {
                <p class="text-muted small mt-2 mb-0">
                    Last password change: @LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </p>
