@using sv_e084aeefa30a434eb3ad6e8eac993555.Models

<div class="appearance-section">
    <h4 class="mb-4">Appearance Settings</h4>

    <div class="row">
        <div class="col-md-7">
            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Theme</h6>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")"
                                   checked="@(Theme == theme)"
                                   @onchange="() => Theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Font Size</h6>
                    <div class="btn-group w-100" role="group">
                        @foreach (var size in new[] { "Small", "Medium", "Large" })
                        {
                            <button type="button"
                                    class="btn @(FontSize == size ? "btn-primary" : "btn-outline-primary")"
                                    @onclick="() => FontSize = size">
                                @size
                            </button>
                        }
                    </div>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <h6 class="card-title mb-3">Language</h6>
                    <select class="form-select" value="@Language"
                            @onchange="e => Language = e.Value?.ToString() ?? Language">
                        <option value="English">English</option>
                        <option value="Spanish">Spanish</option>
                        <option value="French">French</option>
                        <option value="German">German</option>
                        <option value="Japanese">Japanese</option>
                        <option value="Chinese">Chinese</option>
                    </select>
                </div>
            </div>

            <div class="card mb-4">
                <div class="card-body">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode"
                               checked="@CompactMode"
                               @onchange="e => CompactMode = (bool)(e.Value ?? false)" />
                        <label class="form-check-label" for="compactMode">
                            Compact Mode
                            <small class="d-block text-muted">Reduce spacing and padding for a denser layout</small>
                        </label>
                    </div>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="Save" disabled="@IsSaving">
                @if (IsSaving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>

            @if (ShowSuccess)
            {
                <div class="alert alert-success mt-3">✅ Appearance settings saved!</div>
            }
        </div>

        <div class="col-md-5">
            <div class="card">
                <div class="card-header">
                    <h6 class="mb-0">Live Preview</h6>
                </div>
                <div class="card-body preview-area @GetPreviewClasses()">
                    <div class="preview-header mb-2">
                        <strong>Sample Content</strong>
                    </div>
                    <p class="preview-text">
                        This is how your content will look with the selected settings.
                    </p>
                    <div class="d-flex gap-2 mb-2">
                        <button class="btn btn-primary btn-sm">Primary</button>
                        <button class="btn btn-outline-secondary btn-sm">Secondary</button>
                    </div>
                    <ul class="preview-list mb-0">
                        <li>Navigation item one</li>
                        <li>Navigation item two</li>
                        <li>Navigation item three</li>
                    </ul>
                    <div class="mt-2">
                        <small class="text-muted">
                            Theme: @Theme · Font: @FontSize · Lang: @Language
                            @(CompactMode ? " · Compact" : "")
                        </small>
                    </div>
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter] public AppearanceSettings? Settings { get; set; }
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string Theme = "Light";
    private string FontSize = "Medium";
    private string Language = "English";
    private bool CompactMode;
    private bool IsSaving;
    private bool ShowSuccess;
    private bool _initialized;

    protected override void OnParametersSet()
    {
        if (Settings is not null && !_initialized)
        {
            Theme = Settings.Theme;
            FontSize = Settings.FontSize;
            Language = Settings.Language;
            CompactMode = Settings.CompactMode;
            _initialized = true;
        }
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(Theme switch
        {
            "Dark" => "preview-dark",
            "System" => "preview-system",
            _ => "preview-light"
        });
        classes.Add(FontSize switch
        {
            "Small" => "preview-font-sm",
            "Large" => "preview-font-lg",
            _ => "preview-font-md"
        });
        if (CompactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private async Task Save()
    {
        IsSaving = true;
        ShowSuccess = false;
        var updated = new AppearanceSettings(Theme, FontSize, Language, CompactMode);
        await OnSave.InvokeAsync(updated);
        IsSaving = false;
        ShowSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        ShowSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

.preview-area {
    transition: all 0.2s ease;
    border-radius: 0.375rem;
    min-height: 200px;
}

.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
}

.preview-dark .text-muted {
