@page "/settings"
@using sv_e084aeefa30a434eb3ad6e8eac993555.Models
@rendermode InteractiveServer
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <div class="settings-nav">
        <SettingsSidebar ActiveSection="@_activeSection"
                         OnSectionChanged="section => { _activeSection = section; }" />
    </div>

    <div class="settings-content p-4">
        @if (_isLoading)
        {
            <div class="d-flex justify-content-center align-items-center" style="min-height: 300px;">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @switch (_activeSection)
            {
                case "Profile":
                    <ProfileSection Profile="@_profile" OnSave="SaveProfile" />
                    break;
                case "Notifications":
                    <NotificationsSection Prefs="@_notifications" OnSave="SaveNotifications" />
                    break;
                case "Security":
                    <SecuritySection Settings="@_security"
                                     OnChangePassword="ChangePassword"
                                     OnRevokeSession="RevokeSession"
                                     OnTwoFactorToggle="ToggleTwoFactor" />
                    break;
                case "Appearance":
                    <AppearanceSection Settings="@_appearance" OnSave="SaveAppearance" />
                    break;
            }
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";
    private bool _isLoading = true;

    private UserProfile? _profile;
    private NotificationPrefs? _notifications;
    private SecuritySettings? _security;
    private AppearanceSettings? _appearance;

    protected override async Task OnInitializedAsync()
    {
        await LoadAllSettingsAsync();
        _isLoading = false;
    }

    private async Task LoadAllSettingsAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        _profile = profileTask.Result;
        _notifications = notifTask.Result;
        _security = securityTask.Result;
        _appearance = appearanceTask.Result;
    }

    private async Task SaveProfile(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        _profile = profile;
    }

    private async Task SaveNotifications(NotificationPrefs prefs)
    {
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _notifications = prefs;
    }

    private async Task ChangePassword((string Current, string New) data)
    {
        await SettingsService.ChangePasswordAsync(data.Current, data.New);
    }

    private async Task RevokeSession(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private Task ToggleTwoFactor(bool enabled)
    {
        // In a real app this would call the service
        return Task.CompletedTask;
    }

    private async Task SaveAppearance(AppearanceSettings settings)
    {
        await SettingsService.SaveAppearanceAsync(settings);
        _appearance = settings;
    }
}

.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 3.5rem);
    margin: -1rem -1.5rem;
    background: #fff;
}

.settings-nav {
    flex-shrink: 0;
}

.settings-content {
    flex: 1;
    overflow-y: auto;
    max-width: 900px;
}

